        return isSymbol && double.TryParse(input[..index], out _);
    }

    /// <summary>
    /// Replaces a metric prefix name with its corresponding symbol in the input string.
    /// Uses direct lookup instead of iterating all prefixes.
    /// </summary>
    /// <param name="input">The string containing a metric prefix name.</param>
    /// <returns>The string with the prefix name replaced by its symbol.</returns>
    private static string ReplaceNameBySymbol(string input)
    {
        foreach (var entry in NameToSymbol)
        {
            var idx = input.IndexOf(entry.Key, StringComparison.Ordinal);
            if (idx >= 0)
            {
                return string.Concat(input.AsSpan(0, idx), SymbolStrings[entry.Value], input.AsSpan(idx + entry.Key.Length));
