122.     /// <summary>
123.     /// Converts a number to its metric representation using the specified formatting options.
124.     /// </summary>
125.     /// <param name="input">The number to convert.</param>
126.     /// <param name="formats">Formatting options controlling symbol vs name and scale.</param>
127.     /// <param name="decimals">Optional number of decimal places to round to.</param>
128.     /// <returns>A string with the metric representation (e.g., "1.5k" or "1.5 kilo").</returns>
129.     /// <example>
130.     /// <code>
131.     /// 1500.ToMetric() => "1.5k"
132.     /// 1500.ToMetric(MetricFormat.None) => "1.5 kilo"
133.     /// 2500000.ToMetric(MetricFormat.UseSymbol) => "2.5M"
134.     /// </code>
135.     /// </example>
136.     public static string ToMetric(this double input, MetricFormat formats = MetricFormat.UseSymbol, int? decimals = null)
137.     {
138.         if (double.IsNaN(input) || double.IsInfinity(input))
139.         {
140.             return input.ToString();
141.         }
142. 
143.         if (Math.Abs(input) < 1e-24)
144.         {
145.             return "0";
146.         }
147. 
148.         var isNegative = input < 0;
149.         input = Math.Abs(input);
150. 
151.         var exponent = (int)Math.Floor(Math.Log10(input));
152.         var metricExponent = exponent - (exponent % 3);
153. 
154.         if (metricExponent == 0)
155.         {
156.             var formatted = decimals.HasValue ? input.ToString($"F{decimals}") : input.ToString("G");
157.             return isNegative ? $"-{formatted}" : formatted;
158.         }
159. 
160.         if (!ExponentToSymbol.TryGetValue(metricExponent, out var symbol))
161.         {
162.             var fallback = input.ToString("G");
163.             return isNegative ? $"-{fallback}" : fallback;
164.         }
165. 
166.         var scaledValue = input / PowersOf10[metricExponent];
167.         var valueStr = decimals.HasValue ? scaledValue.ToString($"F{decimals}") : scaledValue.ToString("G4");
168. 
169.         var suffix = formats.HasFlag(MetricFormat.UseSymbol)
170.             ? SymbolStrings[symbol]
171.             : $" {GetPrefixName(symbol, formats)}";
172. 
173.         return isNegative ? $"-{valueStr}{suffix}" : $"{valueStr}{suffix}";
174.     }
175. 
176.     /// <summary>
177.     /// Converts a metric string representation back to a number.
178.     /// </summary>
179.     /// <param name="input">The metric string to parse (e.g., "1.5k", "2.5 mega").</param>
180.     /// <returns>The numeric value represented by the metric string.</returns>
181.     /// <exception cref="ArgumentException">Thrown when the input is not a valid metric representation.</exception>
182.     /// <example>
183.     /// <code>
184.     /// "1.5k".FromMetric() => 1500
185.     /// "2.5M".FromMetric() => 2500000
186.     /// "100m".FromMetric() => 0.1
187.     /// </code>
188.     /// </example>
189.     public static double FromMetric(this string input)
190.     {
191.         ArgumentException.ThrowIfNullOrWhiteSpace(input);
192. 
193.         input = input.Trim();
194.         if (double.TryParse(input, out var directParse))
195.         {
196.             return directParse;
197.         }
198. 
199.         // Try symbol-based parsing first
200.         var lastChar = input[^1];
201.         if (UnitPrefixes.TryGetValue(lastChar, out _))
202.         {
203.             var numericPart = input[..^1].Trim();
204.             if (double.TryParse(numericPart, out var value))
205.             {
206.                 var exponent = GetExponentForSymbol(lastChar);
207.                 return value * PowersOf10[exponent];
208.             }
209.         }
210. 
211.         // Try name-based parsing: find a matching prefix name and replace it
212.         var nameInput = ReplaceNameBySymbol(input);
213.         if (nameInput != input)
214.         {
215.             return nameInput.FromMetric();
216.         }
217. 
218.         throw new ArgumentException($"Invalid metric numeral: '{input}'", nameof(input));
219.     }
220. 
221.     /// <summary>
222.     /// Determines whether the given string is a valid metric numeral.
223.     /// </summary>
