226.     public static bool IsValidMetricNumeral(this string input)
227.     {
228.         if (string.IsNullOrWhiteSpace(input))
229.         {
230.             return false;
231.         }
232. 
233.         input = input.Trim();
234.         if (double.TryParse(input, out _))
235.         {
236.             return true;
237.         }
238. 
239.         var index = input.Length - 1;
240.         var last = input[index];
241.         var isSymbol = UnitPrefixes.ContainsKey(last);
242.         return isSymbol && double.TryParse(input[..index], out _);
243.     }
