267.         {
268.             'k' => 3, 'M' => 6, 'G' => 9, 'T' => 12, 'P' => 15, 'E' => 18, 'Z' => 21, 'Y' => 24,
269.             'm' => -3, 'μ' => -6, 'n' => -9, 'p' => -12, 'f' => -15, 'a' => -18, 'z' => -21, 'y' => -24,
270.             _ => 0
271.         };
272. 
