274.     {
275.         if (!UnitPrefixes.TryGetValue(symbol, out var prefix))
276.         {
277.             return SymbolStrings.TryGetValue(symbol, out var str) ? str : symbol.ToString();
278.         }
279. 
280.         return formats.HasFlag(MetricFormat.UseShortScale) ? prefix.ShortScaleWord : prefix.LongScaleWord;
281.     }
